import React from 'react';
import { Link } from 'react-router-dom';
import placeholderImage from '../assets/Heroscreen.jpg';

function PlacesToVisit({ trip }) {

    console.log("itinerary:", trip?.itinerary);

  return (
    <div className='text-black mt-5'>
      <h2 className='font-semibold text-3xl items-center flex justify-center flex-col'>
        Places To Visit
      </h2>
       
      <div className='grid grid-cols-2 md:grid-cols-3 lg:grid-cols-3 mt-3 items-center gap-3 justify-center'>
        {
          // Ensure itinerary exists and is not empty
          trip?.itinerary && Object.keys(trip?.itinerary).length > 0 ? (
            Object.entries(trip?.itinerary).map(([dayKey, dayDetails], index) => (
              <div key={index} className='text-black'>
                <h2 className='font-bold text-lg'>{dayKey}</h2> 
                <p>{dayDetails?.theme}</p> {/* Display theme for each day */}
                
                <div>
                  {/* Display activities for each day */}
                  {dayDetails?.activities && dayDetails?.activities.length > 0 ? (
                    <ul>
                      {dayDetails.activities.map((activity, idx) => (
                        <li key={idx}>{activity}</li> 
                      ))}
                    </ul>
                  ) : (
                    <p>No activities available for this day</p>
                  )}
                </div>

                {/* Render other details like place_name, place, etc. */}
                {dayDetails?.place_name && <p><strong>Place Name:</strong> {dayDetails.place_name}</p>}
                {dayDetails?.place && <p><strong>Place:</strong> {dayDetails.place}</p>}
                {dayDetails?.details && <p><strong>Details:</strong> {dayDetails.details}</p>}
                {dayDetails?.rating && <p><strong>Rating:</strong> {dayDetails.rating}</p>}
                {dayDetails?.place_image_url && (
                  <img src={dayDetails.place_image_url} alt={dayDetails.place_name} className="w-full h-auto" />
                )}
                {dayDetails?.geo_coordinates && <p><strong>Coordinates:</strong> {dayDetails.geo_coordinates}</p>}
                {dayDetails?.ticket_pricing && <p><strong>Ticket Pricing:</strong> {dayDetails.ticket_pricing}</p>}
                {dayDetails?.time_to_travel && <p><strong>Time to Travel:</strong> {dayDetails.time_to_travel}</p>}
                {dayDetails?.best_time_to_visit && <p><strong>Best Time to Visit:</strong> {dayDetails.best_time_to_visit}</p>}
              </div>
            ))
          ) : (
            <p>No places are available</p>
          )
        }
      </div>
    </div>
  );
}

export default PlacesToVisit;
